import base64
import xml.etree.ElementTree as ET


class SAMLValidationError(Exception):
    pass


class SAMLResponseParser:
    NS = {
        "samlp": "urn:oasis:names:tc:SAML:2.0:protocol",
        "saml": "urn:oasis:names:tc:SAML:2.0:assertion",
    }

    def parse_post_response(self, saml_response_b64):
        if not saml_response_b64:
            raise SAMLValidationError("Missing SAMLResponse")

        try:
            xml_bytes = base64.b64decode(saml_response_b64)
        except Exception as exc:
            raise SAMLValidationError("Invalid base64 SAMLResponse") from exc

        try:
            root = ET.fromstring(xml_bytes)
        except ET.ParseError as exc:
            raise SAMLValidationError("Invalid XML in SAMLResponse") from exc

        self._validate_structure(root)

        assertion = root.find("saml:Assertion", self.NS)
        if assertion is None:
            encrypted_assertion = root.find("saml:EncryptedAssertion", self.NS)
            if encrypted_assertion is not None:
                raise SAMLValidationError("EncryptedAssertion is not supported")
            raise SAMLValidationError("Missing Assertion")

        name_id = self._extract_name_id(assertion)
        attributes = self._extract_attributes(assertion)

        return {
            "name_id": name_id,
            "attributes": attributes,
            "raw_xml": xml_bytes.decode("utf-8", errors="replace"),
        }

    def _validate_structure(self, root):
        expected = self._strip_ns(root.tag)
        if expected != "Response":
            raise SAMLValidationError("Root element must be Response")

        status = root.find("samlp:Status", self.NS)
        if status is None:
            raise SAMLValidationError("Missing Status")

        status_code = status.find("samlp:StatusCode", self.NS)
        if status_code is None:
            raise SAMLValidationError("Missing StatusCode")

        assertion = root.find("saml:Assertion", self.NS)
        encrypted_assertion = root.find("saml:EncryptedAssertion", self.NS)
        if assertion is None and encrypted_assertion is None:
            raise SAMLValidationError("Missing Assertion or EncryptedAssertion")

    def _extract_name_id(self, assertion):
        subject = assertion.find("saml:Subject", self.NS)
        if subject is None:
            raise SAMLValidationError("Missing Subject")

        name_id = subject.find("saml:NameID", self.NS)
        if name_id is None or not (name_id.text and name_id.text.strip()):
            raise SAMLValidationError("Missing NameID")

        return name_id.text.strip()

    def _extract_attributes(self, assertion):
        attributes = {}
        for stmt in assertion.findall("saml:AttributeStatement", self.NS):
            for attr in stmt.findall("saml:Attribute", self.NS):
                name = attr.attrib.get("Name")
                if not name:
                    continue
                values = []
                for value_node in attr.findall("saml:AttributeValue", self.NS):
                    if value_node.text is not None:
                        values.append(value_node.text.strip())
                    else:
                        values.append("")
                attributes[name] = values
        return attributes

    def _strip_ns(self, tag):
        if "}" in tag:
            return tag.split("}", 1)[1]
        return tag

# enterprise_saml/views.py
from django.conf import settings
from django.contrib.auth import authenticate, login
from django.http import HttpResponseBadRequest, HttpResponseRedirect
from django.views import View

from .saml import SAMLResponseParser, SAMLValidationError


class AssertionConsumerServiceView(View):
    http_method_names = ["post"]

    def post(self, request, *args, **kwargs):
        saml_response = request.POST.get("SAMLResponse")
        relay_state = request.POST.get("RelayState") or settings.SAML_SP.get("DEFAULT_RELAY_STATE_URL", "/")

        parser = SAMLResponseParser()
        try:
            parsed = parser.parse_post_response(saml_response)
        except SAMLValidationError as exc:
            return HttpResponseBadRequest(str(exc))

        user = authenticate(
            request,
            saml_name_id=parsed["name_id"],
            saml_attributes=parsed["attributes"],
        )
        if user is None:
            return HttpResponseBadRequest("Unable to authenticate SAML user")

        login(request, user, backend="enterprise_saml.auth_backends.SAMLAuthenticationBackend")
        request.session["saml_name_id"] = parsed["name_id"]
        request.session["saml_attributes"] = parsed["attributes"]
        request.session["saml_raw_xml"] = parsed["raw_xml"]

        return HttpResponseRedirect(relay_state)

